func solve(words: Array<String>): Array<Int64> {
    let n = words.length
    let answer = Array<Int64>(repeating: 0, count: n)

    for i in 0..<n {
        let modified = words[0..<i] + words[i+1..<n]
        var max_len: Int64 = 0

        for j in 0..<modified.length-1 {
            let s1 = modified[j]
            let s2 = modified[j+1]
            let min_len = min(s1.length, s2.length)
            var common = 0

            while common < min_len && s1[common] == s2[common] {
                common += 1
            }

            if common > max_len {
                max_len = common
            }
        }

        answer[i] = max_len
    }

    return answer
}
