import Foundation

func solve(words: Array<String>) -> Array<Int64> {
    var answer = [Int64]()
    let n = words.count

    if n == 1 {
        return [0]
    }

    for i in 0..<n {
        var currentWords = words
        currentWords.remove(at: i)
        var maxLen: Int64 = 0

        for j in 0..<currentWords.count - 1 {
            let word1 = currentWords[j]
            let word2 = currentWords[j + 1]
            var commonLen = 0
            let minLength = min(word1.count, word2.count)

            while commonLen < minLength && word1[word1.index(word1.startIndex, offsetBy: commonLen)] == word2[word2.index(word2.startIndex, offsetBy: commonLen)] {
                commonLen += 1
            }

            if commonLen > maxLen {
                maxLen = Int64(commonLen)
            }
        }

        answer.append(maxLen)
    }

    return answer
}
